"use client";

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { WishlistService, CartService } from "@/services/cart.service";
import Image from "next/image";
import { Trash2, ShoppingCart, Loader2 } from "lucide-react";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import toast from "react-hot-toast";

import { Product } from "@/types/product";

export default function WishlistPage() {
  const queryClient = useQueryClient();

  const { data: wishlistData, isLoading } = useQuery({
    queryKey: ["wishlist"],
    queryFn: WishlistService.getWishlist,
  });

  const removeMutation = useMutation({
    mutationFn: WishlistService.removeFromWishlist,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["wishlist"] });
      toast.success("Item removed from wishlist");
    },
  });

  const moveToCartMutation = useMutation({
    mutationFn: async (productId: string) => {
      await CartService.addToCart(productId);
      return WishlistService.removeFromWishlist(productId);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["wishlist"] });
      queryClient.invalidateQueries({ queryKey: ["cart"] });
      toast.success("Item moved to cart");
    },
  });

  if (isLoading) {
    return (
      <div className="flex-1 flex justify-center items-center h-[50vh]">
        <Loader2 className="w-12 h-12 animate-spin text-orange-600" />
      </div>
    );
  }

  const wishlist = wishlistData?.data;

  if (!wishlist || wishlist.length === 0) {
    return (
      <div className="flex-1 flex flex-col justify-center items-center p-12 text-center min-h-[60vh]">
        <div className="w-48 h-48 relative mb-8 opacity-50">
          <Image src="https://cdni.iconscout.com/illustration/premium/thumb/empty-wishlist-7359556-6024625.png" alt="Empty Wishlist" fill className="object-contain" />
        </div>
        <h2 className="text-3xl font-bold mb-3 text-slate-800 dark:text-slate-100">Your Wishlist is Empty!</h2>
        <p className="text-slate-500 mb-8 max-w-sm">Save your favorite items here to review them later.</p>
        <Link href="/products" className="px-8 py-4 bg-orange-600 text-white font-bold rounded-full hover:bg-orange-700 transition shadow-lg shadow-orange-500/30">
          Discover Products
        </Link>
      </div>
    );
  }

  return (
    <div className="bg-slate-50 dark:bg-slate-950 flex-1 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">My Wishlist</h1>
        <p className="text-slate-600 dark:text-slate-400 mb-8 font-medium px-2">
          {wishlist.length} {wishlist.length === 1 ? 'Item' : 'Items'} saved
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          <AnimatePresence>
            {wishlist.map((item: Product) => (
              <motion.div 
                key={item._id}
                layout
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.9 }}
                className="group flex flex-col bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 relative"
              >
                <div className="absolute top-3 right-3 z-10 flex gap-2">
                  <button 
                    onClick={() => removeMutation.mutate(item._id)}
                    className="p-2 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md rounded-full shadow-sm text-red-500 hover:text-white hover:bg-red-500 transition-colors"
                    title="Remove from wishlist"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>

                <Link href={`/products/${item._id}`} className="block relative aspect-square overflow-hidden bg-slate-100 dark:bg-slate-800">
                  <Image 
                    src={item.imageCover} 
                    alt={item.title} 
                    fill
                    className="object-cover group-hover:scale-105 transition-transform duration-500"
                    sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
                  />
                </Link>

                <div className="p-5 flex flex-col flex-1">
                  <Link href={`/products/${item._id}`}>
                    <h3 className="font-semibold text-slate-900 dark:text-white text-lg line-clamp-1 mb-2 group-hover:text-orange-600 transition-colors">
                      {item.title}
                    </h3>
                  </Link>

                  <div className="mt-auto pt-4 flex items-center justify-between border-t border-slate-100 dark:border-slate-800">
                    <span className="font-bold text-xl text-slate-900 dark:text-white">EGP {item.price}</span>
                    <button 
                      onClick={() => moveToCartMutation.mutate(item._id)}
                      disabled={moveToCartMutation.isPending}
                      className="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-800 text-white text-sm font-semibold rounded-lg hover:bg-orange-600 dark:hover:bg-orange-600 transition-colors shadow-sm active:scale-95 disabled:opacity-50"
                    >
                      <ShoppingCart className="w-4 h-4" /> Move
                    </button>
                  </div>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
}
